import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import * as z from "zod/v4";
import { DesignflowClient } from "./clients/designflow-client.js";
import { loadToolConfig } from "./config/settings.js";
import { formatSearchResults, formatSummaryList, formatToolContract, ToolCatalog, toSummary } from "./registry/catalog.js";
import { TOOL_GROUPS } from "./registry/groups.js";
import type { ToolGroup } from "./types.js";

const groupNames = TOOL_GROUPS.map((group) => group.name) as [ToolGroup, ...ToolGroup[]];

const textResult = (text: string) => ({
  content: [{ type: "text" as const, text }],
});

const jsonResult = (value: unknown) => textResult(typeof value === "string" ? value : JSON.stringify(value, null, 2));

const errorResult = (error: unknown) => ({
  content: [
    {
      type: "text" as const,
      text: error instanceof Error ? error.message : String(error),
    },
  ],
  isError: true,
});

export const createDesignflowMcpServer = (cwd = process.cwd()): McpServer => {
  const server = new McpServer({
    name: "designflow-mcp",
    version: "0.1.0",
  });

  const catalog = new ToolCatalog(loadToolConfig(cwd));
  const client = new DesignflowClient();

  server.registerTool(
    "health",
    {
      title: "Health",
      description: "Show MCP server status and enabled hidden capability count.",
      inputSchema: {},
    },
    async () =>
      jsonResult({
        status: "ok",
        name: "designflow-mcp",
        visibleTools: ["health", "list_capabilities", "get_capability_details", "tool_search", "invoke_tool"],
        enabledHiddenCapabilities: catalog.listCapabilities({ limit: 1000 }).length,
        disabledCapabilities: catalog.disabledNames(),
      })
  );

  server.registerTool(
    "list_capabilities",
    {
      title: "List Capabilities",
      description:
        "Browse enabled hidden Designflow operations by group or safety class without invoking them. Use this before invoke_tool.",
      inputSchema: {
        group: z.enum(groupNames).optional().describe("Optional capability group filter."),
        safety: z.number().int().min(1).max(3).optional().describe("Optional safety tier filter."),
        limit: z.number().int().min(1).max(100).optional().describe("Maximum summaries to return."),
      },
    },
    async ({ group, safety, limit }) => {
      const summaries = catalog.listCapabilities({ group, safety, limit });
      const groupCatalog = TOOL_GROUPS.map((entry) => `- ${entry.name}: ${entry.description}`).join("\n");
      return textResult(
        [
          "Enabled Designflow MCP capabilities:",
          "",
          formatSummaryList(summaries),
          "",
          "Groups:",
          groupCatalog,
          "",
          "Next step: call get_capability_details({ name }) for the exact invoke_tool contract.",
        ].join("\n")
      );
    }
  );

  server.registerTool(
    "get_capability_details",
    {
      title: "Get Capability Details",
      description:
        "Inspect one hidden operation's full contract, including args, safety metadata, example invoke_tool call, common failures, and related tools.",
      inputSchema: {
        name: z.string().min(1).describe("Exact hidden capability name returned by list_capabilities or tool_search."),
      },
    },
    async ({ name }) => {
      const tool = catalog.get(name);
      if (!tool) {
        return errorResult(`Unknown or disabled capability: ${name}`);
      }
      return textResult(formatToolContract(tool));
    }
  );

  server.registerTool(
    "tool_search",
    {
      title: "Tool Search",
      description:
        "Search enabled hidden Designflow operations by intent. Returns structured contracts as text so clients do not need every schema in tools/list.",
      inputSchema: {
        query: z.string().min(1).describe("Search terms such as rfq price code, item images, sample photos, grid layout, factory, api docs."),
        limit: z.number().int().min(1).max(30).optional().describe("Maximum contracts to return. Defaults to 8."),
      },
    },
    async ({ query, limit }) => textResult(formatSearchResults(catalog.search(query, limit)))
  );

  server.registerTool(
    "invoke_tool",
    {
      title: "Invoke Tool",
      description:
        "Execute an enabled hidden Designflow operation by exact name. First call tool_search or get_capability_details to get the exact args shape.",
      inputSchema: {
        name: z.string().min(1).describe("Exact hidden capability name."),
        args: z.record(z.string(), z.unknown()).default({}).describe("Arguments matching the capability contract."),
      },
    },
    async ({ name, args }) => {
      const tool = catalog.get(name);
      if (!tool) {
        return errorResult(`Unknown or disabled capability: ${name}`);
      }

      const parsed = tool.argsSchema.safeParse(args ?? {});
      if (!parsed.success) {
        return errorResult(
          [
            `Invalid args for ${name}.`,
            "",
            "Expected:",
            tool.argsDescription,
            "",
            "Validation issues:",
            JSON.stringify(parsed.error.issues, null, 2),
            "",
            "Example:",
            JSON.stringify({ name, args: tool.exampleArgs }, null, 2),
          ].join("\n")
        );
      }

      if (tool.safety.tier !== 1) {
        return errorResult(
          `Capability ${name} is safety tier ${tool.safety.tier}. Write/destructive tools are not enabled in this initial Designflow MCP server.`
        );
      }

      try {
        const result = await tool.invoke(parsed.data, { client, cwd });
        return jsonResult(result);
      } catch (error) {
        return errorResult(error);
      }
    }
  );

  return server;
};

