import type { ConsumerContext } from "./types.js";

const REDACTED = "[redacted]";

const PRICING_KEYS = [
  /(^|_)(cost|costs)($|_)/i,
  /(^|_)(price|prices|pricing)($|_)/i,
  /margin/i,
  /markup/i,
  /royalty/i,
  /commission/i,
  /quote/i,
];

const PII_KEYS = [/email/i, /phone/i, /address/i, /contact/i, /first_?name/i, /last_?name/i];

export const hasScope = (consumer: ConsumerContext, scope: string): boolean => consumer.scopes.has(scope);

export const redactSensitive = (value: unknown, consumer: ConsumerContext): unknown => redactValue(value, consumer);

export const redactArgsForAudit = (value: unknown): unknown => redactValue(value, { id: "audit", scopes: new Set() });

export const capJsonValue = (value: unknown, maxBytes: number): unknown => {
  const serialized = JSON.stringify(value);
  if (Buffer.byteLength(serialized, "utf8") <= maxBytes) {
    return value;
  }

  return {
    truncated: true,
    maxResponseBytes: maxBytes,
    message: "Response exceeded MCP_MAX_RESPONSE_BYTES. Narrow the query or request a smaller page.",
  };
};

const redactValue = (value: unknown, consumer: ConsumerContext): unknown => {
  if (Array.isArray(value)) {
    return value.map((item) => redactValue(item, consumer));
  }

  if (!value || typeof value !== "object") {
    return value;
  }

  const output: Record<string, unknown> = {};
  for (const [key, child] of Object.entries(value)) {
    if (shouldRedactPricing(key, consumer) || shouldRedactPii(key, consumer)) {
      output[key] = REDACTED;
    } else {
      output[key] = redactValue(child, consumer);
    }
  }

  return output;
};

const shouldRedactPricing = (key: string, consumer: ConsumerContext): boolean =>
  !hasScope(consumer, "pricing") && PRICING_KEYS.some((pattern) => pattern.test(key));

const shouldRedactPii = (key: string, consumer: ConsumerContext): boolean =>
  !hasScope(consumer, "pii") && PII_KEYS.some((pattern) => pattern.test(key));

