import { describe, expect, it } from "vitest";
import { capJsonValue, redactArgsForAudit, redactSensitive } from "../../src/policy.js";
import type { ConsumerContext } from "../../src/types.js";

const consumer = (scopes: string[] = []): ConsumerContext => ({ id: "test", scopes: new Set(scopes) });

describe("policy", () => {
  it("redacts pricing and PII fields by default", () => {
    const redacted = redactSensitive(
      {
        item: "123",
        wholesalePrice: 10,
        vendor_email: "buyer@example.com",
        nested: { royalty_rate: 0.12, status: "approved" },
      },
      consumer()
    );

    expect(redacted).toEqual({
      item: "123",
      wholesalePrice: "[redacted]",
      vendor_email: "[redacted]",
      nested: { royalty_rate: "[redacted]", status: "approved" },
    });
  });

  it("reveals scoped fields only for matching scopes", () => {
    const redacted = redactSensitive(
      {
        price: 10,
        email: "buyer@example.com",
      },
      consumer(["pricing"])
    );

    expect(redacted).toEqual({
      price: 10,
      email: "[redacted]",
    });
  });

  it("always redacts audit args", () => {
    expect(redactArgsForAudit({ quoted_cost: 12, phone: "555-1212" })).toEqual({
      quoted_cost: "[redacted]",
      phone: "[redacted]",
    });
  });

  it("caps oversized JSON responses", () => {
    expect(capJsonValue({ value: "x".repeat(100) }, 20)).toEqual({
      truncated: true,
      maxResponseBytes: 20,
      message: "Response exceeded MCP_MAX_RESPONSE_BYTES. Narrow the query or request a smaller page.",
    });
  });
});

