const express = require('express');
const router = express.Router();
const openrouter = require('../helpers/openrouter');
const deepseek = require('../helpers/deepseek');
const qwen = require('../helpers/qwen');
const { authRole } = require('../helpers/auth');
const { cacheMetadata, STRATEGIES, strategyForOpenRouterModel } = require('../helpers/cache-strategy');
const AiCacheTelemetry = require('../services/ai-cache-telemetry.service');

const AI_PROXY_ROLES = ['designer', 'sourcing_manager', 'vendor', 'sales', 'production'];

/**
 * Hardcoded list of models DeepSeek's direct API serves. The shape matches
 * OpenRouter's /models response so the frontend model card renders identically.
 * Pricing is in dollars-per-token (OpenRouter's convention: $0.14/1M → "0.00000014").
 */
const DEEPSEEK_DIRECT_MODELS = {
  data: [
    {
      id: 'deepseek/deepseek-v4-pro',
      name: 'DeepSeek V4 Pro (direct)',
      description: 'Reasoning model with thinking mode. Best HTS classification accuracy. Supports reasoning_effort: high | max.',
      context_length: 128000,
      // prompt = cache-miss input price; prompt_cache = cache-hit input price (~10% of miss)
      pricing: { prompt: '0.00000014', completion: '0.00000028', prompt_cache: '0.000000014' },
      ...cacheMetadata(STRATEGIES.AUTOMATIC_PREFIX, {
        cache_description: 'DeepSeek native automatic disk/prefix cache; no cache_control markers are sent.',
      }),
    },
    {
      id: 'deepseek/deepseek-v4-flash',
      name: 'DeepSeek V4 Flash (direct)',
      description: 'Faster, cheaper non-reasoning chat model. Does NOT support reasoning_effort.',
      context_length: 64000,
      pricing: { prompt: '0.00000007', completion: '0.00000014', prompt_cache: '0.000000007' },
      ...cacheMetadata(STRATEGIES.AUTOMATIC_PREFIX, {
        cache_description: 'DeepSeek native automatic disk/prefix cache; no cache_control markers are sent.',
      }),
    },
  ],
};

function annotateQwenDirectModels(models) {
  return {
    ...models,
    data: (models.data || []).map(model => ({
      ...model,
      ...cacheMetadata(STRATEGIES.SESSION_CACHE),
    })),
  };
}

/**
 * GET /api/openrouter/models?api=openrouter|deepseek-direct|qwen-direct
 * Returns the model list for the chosen API. Defaults to OpenRouter.
 */
router.get('/models', authRole(AI_PROXY_ROLES), async (req, res) => {
  const api = (req.query.api || 'openrouter').toString();
  try {
    if (api === 'deepseek-direct') {
      return res.json(DEEPSEEK_DIRECT_MODELS);
    }
    if (api === 'qwen-direct') {
      const data = await qwen.listModels();
      return res.json(annotateQwenDirectModels(data));
    }
    const data = await openrouter.listUserModels();
    res.json(data);
  } catch (err) {
    const status = err.response?.status ?? 502;
    res.status(status).json({ error: 'Failed to load models', detail: err.message });
  }
});

/**
 * POST /api/openrouter/chat
 * Body: { model, messages, max_tokens?, temperature?, reasoning?, reasoning_effort?, api?, session_id?, telemetry_feature? }
 *
 * `api` ('openrouter' | 'deepseek-direct' | 'qwen-direct'), when provided,
 * forces the routing regardless of the model's prefix. Without it we fall back
 * to auto-detect (deepseek/* models go direct iff DEEPSEEK_API_KEY is set).
 */
router.post('/chat', authRole(AI_PROXY_ROLES), async (req, res) => {
  const { model, messages, max_tokens, temperature, reasoning, reasoning_effort, api, session_id, telemetry_feature } = req.body || {};
  if (!model || !Array.isArray(messages) || messages.length === 0) {
    return res.status(400).json({ error: 'model and messages are required' });
  }

  const useDeepSeekDirect =
    (api === 'deepseek-direct') ||
    (api == null && model.startsWith('deepseek/') && process.env.DEEPSEEK_API_KEY);
  const useQwenDirect =
    (api === 'qwen-direct') ||
    (api == null && model.startsWith('qwen/') && (process.env.DASHSCOPE_API_KEY || process.env.QWEN_API_KEY));

  try {
    let data;
    let provider = 'openrouter';
    let apiBackend = 'openrouter';
    let cacheStrategy = strategyForOpenRouterModel(model);
    if (useDeepSeekDirect) {
      if (!process.env.DEEPSEEK_API_KEY) {
        return res.status(400).json({ error: 'DeepSeek Direct selected but DEEPSEEK_API_KEY is not configured' });
      }
      provider = 'deepseek';
      apiBackend = 'deepseek-direct';
      cacheStrategy = STRATEGIES.AUTOMATIC_PREFIX;
      data = await deepseek.chatCompletion({ model, messages, max_tokens, temperature, reasoning_effort });
    } else if (useQwenDirect) {
      if (!process.env.DASHSCOPE_API_KEY && !process.env.QWEN_API_KEY) {
        return res.status(400).json({ error: 'Qwen Direct selected but DASHSCOPE_API_KEY or QWEN_API_KEY is not configured' });
      }
      provider = 'qwen';
      apiBackend = 'qwen-direct';
      cacheStrategy = session_id ? STRATEGIES.SESSION_CACHE : STRATEGIES.EXPLICIT_CACHE_CONTROL;
      data = await qwen.chatCompletion({ model, messages, max_tokens, temperature, session_id });
    } else {
      data = await openrouter.chatCompletion({ model, messages, max_tokens, temperature, reasoning, session_id });
    }
    AiCacheTelemetry.recordEvent({
      provider,
      api_backend: apiBackend,
      model,
      cache_strategy: cacheStrategy,
      session_id,
      feature: telemetry_feature || 'unknown',
      usage: data?.usage,
    }).catch(err => console.warn('[ai-cache-telemetry] record skipped:', err.message));
    res.json(data);
  } catch (err) {
    const status = err.response?.status ?? 502;
    res.status(status).json({ error: 'Chat completion failed', detail: err.message });
  }
});

module.exports = router;

