const axios = require('axios');
const { normaliseUsage, logCacheMetrics } = require('./cache-metrics');

const DEFAULT_CHAT_BASE = 'https://dashscope-intl.aliyuncs.com/compatible-mode/v1';
const DEFAULT_RESPONSES_BASE = 'https://dashscope-intl.aliyuncs.com/api/v2/apps/protocols/compatible-mode/v1';
const SESSION_TTL_MS = 30 * 60 * 1000;
const sessionState = new Map();

const getChatBaseUrl = () => (
  process.env.QWEN_BASE_URL ||
  process.env.DASHSCOPE_BASE_URL ||
  DEFAULT_CHAT_BASE
).replace(/\/+$/, '');

const getResponsesBaseUrl = () => (
  process.env.QWEN_RESPONSES_BASE_URL ||
  process.env.DASHSCOPE_RESPONSES_BASE_URL ||
  DEFAULT_RESPONSES_BASE
).replace(/\/+$/, '');

const getKey = () => {
  const key = process.env.DASHSCOPE_API_KEY || process.env.QWEN_API_KEY;
  if (!key) throw new Error('DASHSCOPE_API_KEY or QWEN_API_KEY is not configured');
  return key;
};

const headers = () => ({
  Authorization: `Bearer ${getKey()}`,
  'Content-Type': 'application/json',
});

const sessionHeaders = () => ({
  ...headers(),
  'x-dashscope-session-cache': 'enable',
});

const KNOWN_MODEL_METADATA = {
  'qwen-plus': {
    name: 'Qwen Plus (Alibaba direct)',
    description: 'Balanced Qwen text model via Alibaba Cloud Model Studio. Session cache enabled for RFQ AI sessions.',
    context_length: 1000000,
    pricing: {
      prompt: '0.0000004',
      completion: '0.0000012',
      prompt_cache: '0.00000004',
      prompt_cache_write: '0.0000005',
    },
  },
  'qwen-flash': {
    name: 'Qwen Flash (Alibaba direct)',
    description: 'Low-latency Qwen text model via Alibaba Cloud Model Studio. Session cache enabled for RFQ AI sessions.',
    context_length: 1000000,
    pricing: {
      prompt: '0.00000005',
      completion: '0.0000004',
      prompt_cache: '0.000000005',
      prompt_cache_write: '0.0000000625',
    },
  },
};

function toNativeModelId(model) {
  return model.replace(/^qwen\//, '');
}

function toDisplayModelId(model) {
  return model.startsWith('qwen/') ? model : `qwen/${model}`;
}

function normalizeModel(model) {
  const nativeId = typeof model === 'string' ? model : model?.id;
  if (!nativeId) return null;
  const known = KNOWN_MODEL_METADATA[nativeId] || {};
  return {
    id: toDisplayModelId(nativeId),
    name: model?.name || known.name || `${nativeId} (Alibaba direct)`,
    description: model?.description || known.description || 'Alibaba Cloud Model Studio model.',
    context_length: model?.context_length || known.context_length,
    pricing: known.pricing || model?.pricing,
  };
}

exports.listModels = async () => {
  const res = await axios.get(`${getChatBaseUrl()}/models`, {
    headers: headers(),
    timeout: 12000,
  });
  const models = Array.isArray(res.data?.data) ? res.data.data : [];
  return {
    ...res.data,
    data: models.map(normalizeModel).filter(Boolean),
  };
};

function withCacheControl(message) {
  if (typeof message.content !== 'string') return message;
  return {
    ...message,
    content: [{ type: 'text', text: message.content, cache_control: { type: 'ephemeral' } }],
  };
}

function _applyCachingMarkers(messages) {
  const result = messages.map(msg => ({ ...msg }));

  const systemIdx = result.findIndex(m => m.role === 'system');
  if (systemIdx !== -1) result[systemIdx] = withCacheControl(result[systemIdx]);

  let lastAssistantIdx = -1;
  for (let i = result.length - 1; i >= 0; i--) {
    if (result[i].role === 'assistant') { lastAssistantIdx = i; break; }
  }

  if (lastAssistantIdx !== -1) {
    result[lastAssistantIdx] = withCacheControl(result[lastAssistantIdx]);
    return result;
  }

  let lastUserIdx = -1;
  for (let i = result.length - 1; i >= 0; i--) {
    if (result[i].role === 'user') { lastUserIdx = i; break; }
  }
  if (lastUserIdx !== -1) result[lastUserIdx] = withCacheControl(result[lastUserIdx]);

  return result;
}

function messageToInput(message) {
  if (typeof message.content === 'string') {
    return { role: message.role, content: message.content };
  }
  return message;
}

function extractOutputText(data) {
  if (typeof data?.output_text === 'string') return data.output_text;
  const output = Array.isArray(data?.output) ? data.output : [];
  const chunks = [];
  for (const item of output) {
    if (typeof item?.content === 'string') chunks.push(item.content);
    if (Array.isArray(item?.content)) {
      for (const content of item.content) {
        if (typeof content?.text === 'string') chunks.push(content.text);
      }
    }
  }
  return chunks.join('');
}

function toChatCompletionShape(data) {
  const content = extractOutputText(data);
  return {
    ...data,
    choices: data?.choices ?? [{ message: { content } }],
  };
}

function pruneSessionState() {
  const cutoff = Date.now() - SESSION_TTL_MS;
  for (const [key, value] of sessionState.entries()) {
    if ((value.updatedAt || 0) < cutoff) sessionState.delete(key);
  }
}

async function chatCompletionWithSessionCache({ model, messages, max_tokens, temperature, session_id }) {
  pruneSessionState();
  const nativeModel = toNativeModelId(model);
  const previous = sessionState.get(session_id);
  const newMessages = previous
    ? messages.slice(previous.messageCount).filter(message => message.role !== 'assistant')
    : messages;
  const inputMessages = (newMessages.length ? newMessages : messages.slice(-1)).map(messageToInput);
  const body = {
    model: nativeModel,
    input: inputMessages,
    max_output_tokens: max_tokens,
    temperature,
  };

  if (previous?.responseId) {
    body.previous_response_id = previous.responseId;
  }

  const res = await axios.post(`${getResponsesBaseUrl()}/responses`, body, {
    headers: sessionHeaders(),
    timeout: 90000,
  });

  if (res.data?.id) {
    sessionState.set(session_id, {
      responseId: res.data.id,
      messageCount: messages.length,
      updatedAt: Date.now(),
    });
  }

  const data = toChatCompletionShape(res.data);
  if (data?.usage) {
    data.usage = normaliseUsage(data.usage);
    logCacheMetrics('qwen-session', nativeModel, data.usage);
  }
  return data;
}

/**
 * Send a chat completion request directly to Alibaba Cloud Model Studio's
 * OpenAI-compatible Qwen endpoint.
 *
 * Qwen explicit caching uses the same cache_control block shape as Anthropic.
 * We mark the system prompt and the current conversation prefix so repeated
 * turns can read cached tokens instead of reprocessing the full HTS prompt.
 */
exports.chatCompletion = async ({ model, messages, max_tokens = 1024, temperature = 0.2, session_id }) => {
  if (session_id) {
    return chatCompletionWithSessionCache({ model, messages, max_tokens, temperature, session_id });
  }

  const nativeModel = toNativeModelId(model);
  const body = {
    model: nativeModel,
    messages: _applyCachingMarkers(messages),
    max_tokens,
    temperature,
  };

  const res = await axios.post(`${getChatBaseUrl()}/chat/completions`, body, {
    headers: headers(),
    timeout: 90000,
  });

  if (res.data?.usage) {
    res.data.usage = normaliseUsage(res.data.usage);
    logCacheMetrics('qwen', nativeModel, res.data.usage);
  }

  return res.data;
};

exports.toNativeModelId = toNativeModelId;
exports._applyCachingMarkers = _applyCachingMarkers;
exports._sessionState = sessionState;

