const axios = require('axios');
const { normaliseUsage, logCacheMetrics } = require('./cache-metrics');
const { annotateModel, shouldUseCacheControl } = require('./cache-strategy');

const BASE = 'https://openrouter.ai/api/v1';

const getKey = () => {
  const key = process.env.OPENROUTER_API_KEY;
  if (!key) {
    throw new Error('OPENROUTER_API_KEY is not configured');
  }
  return key;
};

const headers = () => ({
  Authorization: `Bearer ${getKey()}`,
  'HTTP-Referer': process.env.WEB_URL || 'https://designflow.app',
  'X-Title': 'DesignFlow PLM',
  'Content-Type': 'application/json',
});

/**
 * List the models available to the configured OpenRouter account.
 * Returns the response from GET /api/v1/models (all available models).
 */
exports.listUserModels = async () => {
  const res = await axios.get(`${BASE}/models/user`, {
    headers: headers(),
    timeout: 12000,
  });
  return {
    ...res.data,
    data: Array.isArray(res.data?.data) ? res.data.data.map(annotateModel) : res.data?.data,
  };
};

/**
 * Providers that support the cache_control content-block format via OpenRouter.
 * OpenAI is excluded — it caches automatically with no markers needed.
 */
/**
 * Add cache_control breakpoints for providers that support the content-block
 * caching format via OpenRouter:
 *   - anthropic/*  — ephemeral cache, 5-min TTL
 *   - deepseek/*   — same cache_control syntax as Anthropic
 *   - google/*     — implicit context caching via OpenRouter
 *   - qwen/*       — Alibaba explicit cache breakpoints via OpenRouter
 *
 * Two breakpoints per turn:
 *   1. system message  → caches the static ~3,600-token system prompt after turn 1
 *   2. last assistant  → caches the growing conversation history each turn
 *      (or the last user message on the first turn before an assistant exists)
 *
 * OpenAI is left unchanged — it caches repeated prefixes automatically.
 * Other providers ignore unknown content-block fields.
 *
 * @param {string} model     OpenRouter model ID (e.g. "anthropic/claude-sonnet-4-5")
 * @param {Array}  messages  [{role, content: string}]
 * @returns {Array} new array with cache_control injected where appropriate
 */
function _applyCachingMarkers(model, messages) {
  if (!shouldUseCacheControl(model)) return messages;

  const result = messages.map(msg => ({ ...msg }));

  // Cache the system prompt (always the same ~3,600 token block)
  const systemIdx = result.findIndex(m => m.role === 'system');
  if (systemIdx !== -1 && typeof result[systemIdx].content === 'string') {
    result[systemIdx] = {
      ...result[systemIdx],
      content: [{ type: 'text', text: result[systemIdx].content, cache_control: { type: 'ephemeral' } }],
    };
  }

  // Cache the last assistant message to freeze accumulated conversation history.
  // On each subsequent turn only the new user message is uncached.
  let lastAssistantIdx = -1;
  for (let i = result.length - 1; i >= 0; i--) {
    if (result[i].role === 'assistant') { lastAssistantIdx = i; break; }
  }
  if (lastAssistantIdx !== -1 && typeof result[lastAssistantIdx].content === 'string') {
    result[lastAssistantIdx] = {
      ...result[lastAssistantIdx],
      content: [{ type: 'text', text: result[lastAssistantIdx].content, cache_control: { type: 'ephemeral' } }],
    };
  } else {
    // First turn: cache the full stable prefix through the initial user message.
    // This helps silent retries and provider sticky routing without waiting for
    // an assistant turn to exist.
    let lastUserIdx = -1;
    for (let i = result.length - 1; i >= 0; i--) {
      if (result[i].role === 'user') { lastUserIdx = i; break; }
    }
    if (lastUserIdx !== -1 && typeof result[lastUserIdx].content === 'string') {
      result[lastUserIdx] = {
        ...result[lastUserIdx],
        content: [{ type: 'text', text: result[lastUserIdx].content, cache_control: { type: 'ephemeral' } }],
      };
    }
  }

  return result;
}

exports._applyCachingMarkers = _applyCachingMarkers;

/**
 * Send a chat completion request to OpenRouter.
 * messages: array of { role, content } following OpenAI chat format.
 * Prompt caching markers are applied automatically for anthropic/*, deepseek/*,
 * and google/* models. OpenAI caches automatically with no markers needed.
 */
exports.chatCompletion = async ({ model, messages, max_tokens = 1024, temperature = 0.2, reasoning, session_id }) => {
  const cachedMessages = _applyCachingMarkers(model, messages);
  const body = { model, messages: cachedMessages, max_tokens, temperature };
  if (reasoning) body.reasoning = reasoning;
  if (session_id) body.session_id = session_id;
  const res = await axios.post(
    `${BASE}/chat/completions`,
    body,
    { headers: headers(), timeout: 90000 }
  );
  if (res.data?.usage) {
    res.data.usage = normaliseUsage(res.data.usage);
    logCacheMetrics('openrouter', model, res.data.usage);
  }
  return res.data;
};
